func TestSchemaV3Migration_Idempotent(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	s, err := Open(dbPath)
	if err != nil {
		t.Fatalf("first open: %v", err)
	}
	s.Close()

	s, err = Open(dbPath)
	if err != nil {
		t.Fatalf("second open: %v", err)
	}
	defer s.Close()
	var triggerCount int
	if err := s.DB().QueryRow(`SELECT COUNT(*) FROM sqlite_master WHERE type = 'trigger' AND name IN ('messages_ai', 'messages_au', 'messages_ad')`).Scan(&triggerCount); err != nil {
		t.Fatalf("count triggers: %v", err)
	}
	if triggerCount != 3 {
		t.Fatalf("trigger count = %d want 3", triggerCount)
	}
}
